content.query:
union isfuzzy=true
(datatable(d:string)[]),
(let total = toscalar(SpyCloudBreachWatchlist_CL | where TimeGenerated {TimeRange} | where severity >= 20 | summarize dcount(email));
let remediated = toscalar(SpyCloud_ConditionalAccessLogs_CL | where TimeGenerated {TimeRange} | summarize dcount(user_principal_name_s));
let mdeActioned = toscalar(Spycloud_MDE_Logs_CL | where TimeGenerated {TimeRange} | summarize dcount(device_name_s));
datatable(Metric:string, Value:long)["High-Sev Users Identified", total, "Users Remediated (CA)", remediated, "Devices Actioned (MDE)", mdeActioned, "Remediation Rate %", iff(total > 0, (remediated * 100) / total, 0)])
